%[text] # 例5.1（縮小処理）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example05_01"; % mfilename
imgname = "msipimg02";
%imgname = "msipimg07";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(rgb2gray(imread(imgfile,imgfmt)),[96 96],'bilinear');
%%
%[text] ## 幾何処理前の画像表示
figure(1) %[output:64078bdf]
imshow(X)  %[output:64078bdf]
title('原画像')  %[output:64078bdf]
%%
%[text] ## 間引き処理処理
U = downsample(downsample(X.',2).',2); % 縮小
figure(2) %[output:9240ac70]
imshow(U) %[output:9240ac70]
title('間引き処理')  %[output:9240ac70]

%%
%[text] ## ブロック平均処理
Y = imresize(X,0.5,'box'); % 縮小
figure(3) %[output:0e216ee2]
imshow(Y) %[output:0e216ee2]
title('ブロック平均処理')  %[output:0e216ee2]


%%
%[text] ## 結果出力
imwrite(X,fullfile(resfolder,"fig05-01a.png"))
imwrite(U,fullfile(resfolder,"fig05-01b.png"))
imwrite(Y,fullfile(resfolder,"fig05-01c.png"))
%%
